class Solution {
public:
    string maximumBinaryString(string binary) {
        int ones = 0, zeros = 0;
        for (char c : binary) {
            if (c == '1') ones++;
            else zeros++;
        }
        string res = "";
        while (zeros > 0) {
            res += "1";
            zeros--;
        }
        res += "10";
        while (ones > 0) {
            res += "0";
            ones--;
        }
        return res;
    }
};
